class Solution:
    def minChanges(self, n: int, k: int) -> int:
        # Check if k is a subset of n's bits using bitwise AND
        if (n & k) != k:
            return -1  # Impossible case: k has a bit set where n does not

        # Count the number of bits that need to be changed
        # This is the number of set bits in (n ^ k), which represents differing bits
        return bin(n ^ k).count('1')
